        </div>
      </nav>
      {isMenuOpen && (
        <motion.div
          initial={{ x: '100%' }}
          animate={{ x: 0 }}
          className="md:hidden bg-off-white dark:bg-light-navy fixed top-0 right-0 h-full w-2/3 shadow-2xl z-50 backdrop-blur-xl"
